INSERT INTO TBL_USERLOCALINFO (
	USERID,   TIMEZONE,   LANG,   TENANT_ID
)
VALUES (
	#userID#, #timeZone#, #lang#, #v_TENANT_ID#
)


INSERT INTO TBL_USER_CONFIG (
	TENANT_ID, USER_ID, PROPERTY_NAME, PROPERTY_VALUE
)
VALUES (
	#tenant_id#, #user_id#, #property_name#, #property_value#
)


INSERT INTO TBL_COMPANY_CONFIG (
	TENANT_ID, COMPANY_ID, PROPERTY_NAME, PROPERTY_VALUE
)
VALUES (
	#tenantID#, #companyID#, #propertyName#, #propertyValue#
)

sqlMap.statement:
    {call	
		DECLARE 
    		column_exists EXCEPTION;
    		pragma exception_init (column_exists , -01430);
		BEGIN 
    		EXECUTE IMMEDIATE  'ALTER TABLE TBL_CONNECTION_INFO	
    							ADD	(
    								STATUS			VARCHAR2(1)		DEFAULT	NULL, 
    								DISCONNECTTIME	DATE			DEFAULT	NULL,
									SESSIONCODE		VARCHAR2(200)	DEFAULT NULL
    								)';
    		EXCEPTION WHEN column_exists THEN NULL;
		END
	}


    {call	
		DECLARE 
    		column_exists EXCEPTION;
    		pragma exception_init (column_exists , -01430);
		BEGIN 
    		EXECUTE IMMEDIATE  'ALTER TABLE TBL_DEV_MASTER	
    							ADD	(
    								PIN 				VARCHAR(1000) 	DEFAULT NULL,
									PINSTATE			CHAR(1)			DEFAULT ''N'',
									BIOMETRIC			CHAR(1)			DEFAULT ''N''
    								)';
    		EXCEPTION WHEN column_exists THEN NULL;
		END
	}

